7187 /// The base class for shuffle instruction emission and shuffle cost estimation.
7188 class BaseShuffleAnalysis {
7189 protected:
7190   /// Checks if the mask is an identity mask.
7191   /// \param IsStrict if is true the function returns false if mask size does
7192   /// not match vector size.
7193   static bool isIdentityMask(ArrayRef<int> Mask, const FixedVectorType *VecTy,
7194                              bool IsStrict) {
7195     int Limit = Mask.size();
7196     int VF = VecTy->getNumElements();
7197     int Index = -1;
7198     if (VF == Limit && ShuffleVectorInst::isIdentityMask(Mask, Limit))
7199       return true;
7200     if (!IsStrict) {
7201       // Consider extract subvector starting from index 0.
7202       if (ShuffleVectorInst::isExtractSubvectorMask(Mask, VF, Index) &&
7203           Index == 0)
7204         return true;
7205       // All VF-size submasks are identity (e.g.
7206       // <poison,poison,poison,poison,0,1,2,poison,poison,1,2,3> etc. for VF 4).
7207       if (Limit % VF == 0 && all_of(seq<int>(0, Limit / VF), [=](int Idx) {
7208             ArrayRef<int> Slice = Mask.slice(Idx * VF, VF);
7209             return all_of(Slice, [](int I) { return I == PoisonMaskElem; }) ||
7210                    ShuffleVectorInst::isIdentityMask(Slice, VF);
7211           }))
7212         return true;
7213     }
7214     return false;
7215   }
