7219   /// change the size of the vector, \p LocalVF is the original size of the
7220   /// shuffled vector.
7221   static void combineMasks(unsigned LocalVF, SmallVectorImpl<int> &Mask,
7222                            ArrayRef<int> ExtMask) {
7223     unsigned VF = Mask.size();
7224     SmallVector<int> NewMask(ExtMask.size(), PoisonMaskElem);
